      service.onElection(0, 5);

      verify(runtime, times(1)).scheduleLoadOperation(
          new TopicPartition(Topic.GROUP_METADATA_TOPIC_NAME, 0),
          5
      );
  }

  @Test
  public void testOnResignationUnloadsGroupMetadataPartition() throws Exception {
      CoordinatorRuntime<GroupCoordinatorShard, CoordinatorRecord> runtime = mockRuntime();
      GroupCoordinatorService service = new GroupCoordinatorServiceBuilder()
          .setConfig(createConfig())
          .setRuntime(runtime)
          .build(true);

      service.onResignation(0, OptionalInt.of(5));

      verify(runtime, times(1)).scheduleUnloadOperation(
          new TopicPartition(Topic.GROUP_METADATA_TOPIC_NAME, 0),
          OptionalInt.of(5)
      );
  }

  @Test
  public void testOnElectionWhenNotActive() throws Exception {
      CoordinatorRuntime<GroupCoordinatorShard, CoordinatorRecord> runtime = mockRuntime();
